import sys, os, json, sqlite3, glob, re

def main():
    inputs = json.loads(os.environ.get('SKILL_INPUTS', '{}'))
    source_dir = inputs.get('sourceDir', '')
    db_path = inputs.get('dbPath', '')
    table_name = inputs.get('tableName', 'records')
    excludes = set(inputs.get('excludePatterns', ['manifest.json', 'sources.json', 'crawl-log.jsonl', '.DS_Store']))

    if not source_dir or not db_path:
        print(json.dumps({'error': 'sourceDir and dbPath required'}))
        return

    # Find all JSON files
    json_files = []
    for root, dirs, files in os.walk(source_dir):
        for f in files:
            if f.endswith('.json') and f not in excludes:
                json_files.append(os.path.join(root, f))

    if not json_files:
        print(json.dumps({'error': f'No JSON files found in {source_dir}', 'searched': source_dir}))
        return

    # Load all records from all files
    all_records = []
    files_summary = []
    for fp in sorted(json_files):
        try:
            with open(fp) as fh:
                data = json.load(fh)
            if isinstance(data, list):
                records = data
            elif isinstance(data, dict):
                # If it's a dict of lists, flatten
                if all(isinstance(v, list) for v in data.values()):
                    records = []
                    for key, items in data.items():
                        for item in items:
                            if isinstance(item, dict):
                                item['_source_key'] = key
                                records.append(item)
                else:
                    records = [data]
            else:
                continue

            # Tag each record with source file
            rel_path = os.path.relpath(fp, source_dir)
            for r in records:
                if isinstance(r, dict):
                    r['_source_file'] = rel_path

            all_records.extend(records)
            files_summary.append({'file': rel_path, 'records': len(records)})
        except Exception as e:
            files_summary.append({'file': os.path.relpath(fp, source_dir), 'error': str(e)})

    if not all_records:
        print(json.dumps({'error': 'No records found in any JSON file', 'files': files_summary}))
        return

    # Collect all unique keys across all records for schema
    all_keys = set()
    for r in all_records:
        if isinstance(r, dict):
            all_keys.update(r.keys())
    all_keys = sorted(all_keys)

    # Create database and table
    os.makedirs(os.path.dirname(db_path) or '.', exist_ok=True)
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()

    # Create table with TEXT columns for flexibility
    cols_def = ', '.join(f'"{k}" TEXT' for k in all_keys)
    cur.execute(f'CREATE TABLE IF NOT EXISTS "{table_name}" (id INTEGER PRIMARY KEY AUTOINCREMENT, {cols_def})')

    # Insert records
    placeholders = ', '.join(['?'] * len(all_keys))
    col_names = ', '.join(f'"{k}"' for k in all_keys)
    inserted = 0
    for r in all_records:
        if not isinstance(r, dict):
            continue
        values = []
        for k in all_keys:
            v = r.get(k)
            if isinstance(v, (dict, list)):
                values.append(json.dumps(v))
            elif v is None:
                values.append(None)
            else:
                values.append(str(v))
        try:
            cur.execute(f'INSERT INTO "{table_name}" ({col_names}) VALUES ({placeholders})', values)
            inserted += 1
        except Exception:
            pass

    conn.commit()

    # Summary
    cur.execute(f'SELECT COUNT(*) FROM "{table_name}"')
    total = cur.fetchone()[0]
    cur.execute(f'SELECT sql FROM sqlite_master WHERE name="{table_name}"')
    schema = cur.fetchone()[0]
    conn.close()

    print(json.dumps({
        'dbPath': db_path,
        'tableName': table_name,
        'totalRecords': total,
        'insertedThisRun': inserted,
        'columns': all_keys,
        'schema': schema,
        'filesSummary': files_summary
    }))

if __name__ == '__main__':
    main()
